     1→import { drizzle } from 'drizzle-orm/pg-js';
     2→import pg from 'pg';
     3→import * as schema from './schema.js';
     4→import { logger } from '../shared/logger.js';
     5→
     6→let _db: ReturnType<typeof drizzle<typeof schema>> | null = null;
     7→let _pool: pg.Pool | null = null;
     8→
     9→export function createDbClient(databaseUrl: string) {
    10→  if (_db) return _db;
    11→
    12→  _pool = new pg.Pool({
    13→    connectionString: databaseUrl,
    14→    max: 20,
    15→    idleTimeoutMillis: 30000,
    16→    connectionTimeoutMillis: 5000,
    17→  });
    18→
    19→  _pool.on('error', (err) => {
    20→    logger.error({ err }, 'Unexpected database pool error');
    21→  });
    22→
    23→  _db = drizzle(_pool, { schema });
    24→  return _db;
    25→}
    26→
    27→export function getDb() {
    28→  if (!_db) throw new Error('Database not initialized. Call createDbClient() first.');
    29→  return _db;
    30→}
    31→
    32→export function getPool() {
    33→  if (!_pool) throw new Error('Database pool not initialized.');
    34→  return _pool;
    35→}
    36→
    37→export async function closeDb() {
    38→  if (_pool) {
    39→    await _pool.end();
    40→    _pool = null;
    41→    _db = null;
    42→  }
    43→}
    44→
    45→export type Database = ReturnType<typeof createDbClient>;
    46→

