     2→import { migrate } from 'drizzle-orm/pg-js/migrator';
     3→import pg from 'pg';
     4→
     5→async function main() {
     6→  const databaseUrl = process.env['DATABASE_URL'];
     7→  if (!databaseUrl) {
     8→    console.error('DATABASE_URL is required');
     9→    process.exit(1);
    10→  }
    11→
    12→  const pool = new pg.Pool({ connectionString: databaseUrl });
    13→  const db = drizzle(pool);
    14→
    15→  console.log('Running migrations...');
    16→  await migrate(db, { migrationsFolder: './drizzle' });
    17→  console.log('Migrations complete.');
    18→
    19→  await pool.end();
    20→}
    21→
    22→main().catch((err) => {
    23→  console.error('Migration failed:', err);
    24→  process.exit(1);
    25→});
